import React, { useEffect, useState } from "react";
import {
  Box,
  Card,
  CardContent,
  Typography,
  Button,
  Grid,
  CircularProgress,
  Snackbar,
  Alert,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { getRiderStatus, getRideHistory } from "../../services/api";
import { useAuth } from "../../contexts/AuthContext"; // ✅ import AuthContext

export default function RiderDashboard() {
  const [rider, setRider] = useState(null);
  const [rides, setRides] = useState([]);
  const [loading, setLoading] = useState(false);
  const [snackbar, setSnackbar] = useState({
    open: false,
    message: "",
    type: "success",
  });

  const { logout } = useAuth(); // ✅ use logout from context
  const navigate = useNavigate();

  const fetchRiderData = async () => {
    try {
      setLoading(true);
      const res = await getRiderStatus();
      setRider(res.data.user || null); // API returns { success, user }
    } catch (err) {
      console.error("❌ Rider status error:", err);
      navigate("/rider-login"); // redirect on 401
    } finally {
      setLoading(false);
    }
  };

  const fetchRideHistory = async () => {
    try {
      const res = await getRideHistory();
      setRides(res.data.rides || []);
    } catch (err) {
      console.error("❌ Ride history error:", err);
      setSnackbar({
        open: true,
        message: "Failed to load ride history",
        type: "error",
      });
    }
  };

  useEffect(() => {
    fetchRiderData();
    fetchRideHistory();
  }, []);

  const handleLogout = () => {
    logout(); // ✅ this clears auth + localStorage
    navigate("/rider-login");
  };

  return (
    <Box p={4}>
      <Typography variant="h4" gutterBottom>
        Rider Dashboard
      </Typography>

      {loading ? (
        <CircularProgress />
      ) : rider ? (
        <Card sx={{ mb: 3, borderRadius: 3, boxShadow: 3 }}>
          <CardContent>
            <Typography variant="h6">{rider.fullName}</Typography>
            <Typography>Email: {rider.email}</Typography>
            <Typography>Mobile: {rider.mobile}</Typography>
            <Typography>
              Approval Status:{" "}
              <b
                style={{
                  color: rider.approvalStatus === "approved" ? "green" : "orange",
                }}
              >
                {rider.approvalStatus || "pending"}
              </b>
            </Typography>
            <Box mt={2}>
              <Button variant="contained" color="error" onClick={handleLogout}>
                Logout
              </Button>
            </Box>
          </CardContent>
        </Card>
      ) : (
        <Typography color="error">No rider data available</Typography>
      )}

      <Typography variant="h5" gutterBottom>
        Ride History
      </Typography>
      <Grid container spacing={2}>
        {rides.length === 0 ? (
          <Typography>No rides found</Typography>
        ) : (
          rides.map((ride) => (
            <Grid item xs={12} md={6} key={ride._id}>
              <Card sx={{ borderRadius: 3, boxShadow: 2 }}>
                <CardContent>
                  <Typography>From: {ride.pickup}</Typography>
                  <Typography>To: {ride.drop}</Typography>
                  <Typography>
                    Date: {new Date(ride.createdAt).toLocaleString()}
                  </Typography>
                  <Typography>Status: {ride.status}</Typography>
                </CardContent>
              </Card>
            </Grid>
          ))
        )}
      </Grid>

      <Snackbar
        open={snackbar.open}
        autoHideDuration={3000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
      >
        <Alert severity={snackbar.type}>{snackbar.message}</Alert>
      </Snackbar>
    </Box>
  );
}
